#include <limits.h>

int safe_abs(int x, int *out) {
    if (x == INT_MIN) return -1;
    *out = x < 0 ? -x : x;
    return 0;
}

tests:
#include <assert.h>
#include <limits.h>
int main(void) {
    int r;
    assert(safe_abs(-7, &r) == 0 && r == 7);
    assert(safe_abs(5, &r) == 0 && r == 5);
    assert(safe_abs(INT_MIN, &r) == -1);
    return 0;
}

