#include <limits.h>

int clamp_int(int v, int lo, int hi) {
    if (v < lo) return lo;
    if (v > hi) return hi;
    return v;
}

int int_bits(void) {
    int bits = 1;              /* sign bit */
    unsigned int m = INT_MAX;
    while (m) { bits++; m >>= 1; }
    return bits;
}

tests:
#include <assert.h>
int main(void) {
    assert(clamp_int(5, 0, 10) == 5);
    assert(clamp_int(-3, 0, 10) == 0);
    assert(clamp_int(99, 0, 10) == 10);
    assert(int_bits() == 32 || int_bits() == 64 || int_bits() == 16);
    return 0;
}

