#include <ctype.h>

int count_vowels(const char *s) {
    int n = 0;
    for (; *s; s++) {
        int c = tolower((unsigned char)*s);
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') n++;
    }
    return n;
}

tests:
#include <assert.h>
int main(void) {
    assert(count_vowels("Hello World") == 3);
    assert(count_vowels("XYZ") == 0);
    assert(count_vowels("AEIOUaeiou") == 10);
    assert(count_vowels("") == 0);
    return 0;
}

