#include <ctype.h>

char *caesar_shift(char *s, int k) {
    k = ((k % 26) + 26) % 26;
    for (char *p = s; *p; p++) {
        unsigned char c = (unsigned char)*p;
        if (isupper(c)) *p = (char)('A' + (c - 'A' + k) % 26);
        else if (islower(c)) *p = (char)('a' + (c - 'a' + k) % 26);
    }
    return s;
}

tests:
#include <assert.h>
#include <string.h>
int main(void) {
    char a[] = "abcXYZ 1!";
    caesar_shift(a, 3);
    assert(strcmp(a, "defABC 1!") == 0);
    char b[] = "Hello";
    caesar_shift(b, 26);
    assert(strcmp(b, "Hello") == 0);
    return 0;
}

