#include <math.h>

int is_prime(int n) {
    if (n < 2) return 0;
    if (n % 2 == 0) return n == 2;
    int limit = (int)sqrt((double)n);
    for (int d = 3; d <= limit; d += 2)
        if (n % d == 0) return 0;
    return 1;
}

tests:
#include <assert.h>
int main(void) {
    assert(is_prime(2) == 1);
    assert(is_prime(17) == 1);
    assert(is_prime(1) == 0);
    assert(is_prime(15) == 0);
    assert(is_prime(97) == 1);
    return 0;
}

