#include <stdlib.h>
#include <stddef.h>

typedef struct Node {
    int value;
    struct Node *next;
} Node;

void push_front(Node **head, int value) {
    Node *n = (Node *)malloc(sizeof(Node));
    n->value = value;
    n->next = *head;
    *head = n;
}

int list_length(const Node *head) {
    int len = 0;
    for (const Node *p = head; p; p = p->next) len++;
    return len;
}

tests:
#include <assert.h>
#include <stddef.h>
int main(void) {
    Node *head = NULL;
    assert(list_length(head) == 0);
    push_front(&head, 3);
    push_front(&head, 2);
    push_front(&head, 1);
    assert(list_length(head) == 3);
    assert(head->value == 1 && head->next->value == 2);
    return 0;
}

