#include <stdlib.h>
#include <string.h>

char *str_reverse_dup(const char *s) {
    size_t n = strlen(s);
    char *out = (char *)malloc(n + 1);
    if (!out) return NULL;
    for (size_t i = 0; i < n; i++)
        out[i] = s[n - 1 - i];
    out[n] = '\0';
    return out;
}

tests:
#include <assert.h>
#include <string.h>
#include <stdlib.h>
int main(void) {
    char *r = str_reverse_dup("abcde");
    assert(strcmp(r, "edcba") == 0);
    free(r);
    char *e = str_reverse_dup("");
    assert(strcmp(e, "") == 0);
    free(e);
    return 0;
}

